INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0, 0.0, 43, -363.0, "2015/12/17 15:00:00", 43001, 1, "ペコリーヌ", 1, "ここからアリーナに\n挑戦できますよ！\n編成を工夫してライバルに\n挑んじゃいましょう！", 1, "2030/12/17 14:59:59", 0.0, 0, 105801);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0, 0.0, 43, -363.0, "2015/12/17 15:00:00", 43002, 1, "コッコロ", 1, "こちらからアリーナに\n挑戦することができます。\n主さまらしい編成で\nライバルに挑みましょう。", 1, "2030/12/17 14:59:59", 0.0, 0, 105901);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0, 0.0, 43, -363.0, "2015/12/17 15:00:00", 43003, 1, "キャル", 1, "ここからアリーナに\n挑戦できるわよ！\nしっかり編成を考えて\nライバルに挑みなさい！", 1, "2030/12/17 14:59:59", 0.0, 0, 106001);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0, 0.0, 44, -416.5, "2015/12/17 15:00:00", 43004, 1, "アメス", 1, "ミッションをクリアすると報酬が\n受け取れるわ。ジャンジャン\nクリアしてバリバリ強化して\nあげなさい♪", 1, "2030/12/17 14:59:59", 0.0, 0, 123001);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0, 0.0, 44, -416.5, "2015/12/17 15:00:00", 43005, 1, "アメス", 2, "ぼんやりしてる場合じゃないわ。\n早くミッションをクリアして\n報酬を受け取ってきなさい！", 1, "2030/12/17 14:59:59", 0.0, 0, 123001);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0, 0.0, 45, -416.5, "2015/12/17 15:00:00", 43006, 1, "アメス", 3, "ちょっとあんた、報酬が\n受け取れるじゃない！\n忘れずにチェックなさい。\nアメス様との約束よ？", 2, "2030/12/17 14:59:59", 5.79, 0, 123001);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0, 0.0, 46, -371.5, "2015/12/17 15:00:00", 46001, 1, "アメス", 1, "はい、お疲れさま。\nここではマスタリーチケットを\n使って、マスタリー強化素材を\n手に入れることができるわよ。", 1, "2030/12/17 14:59:59", 0.0, 0, 123001);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0, 0.0, 47, -416.5, "2015/12/17 15:00:00", 47001, 2, "シズル", 1, "呼ばれて飛び出てお姉ちゃんだよ♪\nたとえ火の中、水の中、迷宮の中っ\nこのダンジョンを踏破できるよう\n弟くんを応援してあげるからねっ♪", 2, "2030/12/17 14:59:59", 0.0, 0, 104901);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0, 0.0, 47, -416.5, "2015/12/17 15:00:00", 47002, 1, "リノ", 1, "ほんとーに不思議な場所ですね～\nお兄ちゃんが冒険を頑張れるよう\nおまじないをかけてあげますねっ\nフレーフレー、お・兄・ちゃんっ♪", 2, "2030/12/17 14:59:59", 9.32, 0, 101101);
